svg.script:
const data = [
  { 
    title: "مساحة إعلانية متاحة", 
    desc: 'تواصل مع إدارة "صوان" لحجز هذه المساحة', 
    dir: "rtl" 
  },
  { 
    title: "Advertising space available", 
    desc: "Contact Siwane management to reserve this space", 
    dir: "ltr" 
  }
];

const mainEl = document.getElementById("text-main");
const subEl = document.getElementById("text-sub");

// تعيين اتجاه النص بشكل صحيح باستخدام CSS
function setDirection(el, dir) {
  el.style.direction = dir;
  el.style.unicodeBidi = dir === "rtl" ? "embed" : "normal";
}

// تأثير تلاشي تدريجي
function fadeOut(el, duration = 400) {
  return new Promise(resolve => {
    el.style.transition = `opacity ${duration}ms`;
    el.style.opacity = 0;
    setTimeout(() => {
      el.textContent = "";
      el.style.opacity = 1;
      el.style.transition = "none";
      resolve();
    }, duration);
  });
}

async function typeText(el, text, speed, showCursor = true) {
  el.textContent = "";
  let cursor = showCursor ? "|" : "";
  for (let i = 0; i <= text.length; i++) {
    el.textContent = text.substring(0, i) + (i < text.length ? cursor : "");
    await new Promise(r => setTimeout(r, speed));
    // إيقاف المؤشر آخر حرف لفترة أطول قليلاً
    if (i === text.length - 1) await new Promise(r => setTimeout(r, 300));
  }
  // إزالة المؤشر بعد الانتهاء
  el.textContent = text;
}

async function startLoop() {
  let i = 0;
  while (true) {
    let item = data[i % 2];

    setDirection(mainEl, item.dir);
    setDirection(subEl, item.dir);

    await typeText(mainEl, item.title, 80);  // سرعة معدّلة
    await typeText(subEl, item.desc, 40);    // سرعة معدّلة للوصف

    // الانتظار 6 ثوانٍ قبل الإخفاء
    await new Promise(r => setTimeout(r, 6000));

    // إخفاء تدريجي
    await fadeOut(mainEl, 500);
    await fadeOut(subEl, 500);

    // فاصل بسيط قبل الجملة التالية
    await new Promise(r => setTimeout(r, 500));
    i++;
  }
}

startLoop();
